  const capabilities = agentEntry?.handshake.capabilities || [];
  const persona = AGENT_PERSONAS[agentId] || `Du er ${displayName} med capabilities: ${capabilities.join(", ")}. Du svarer kort og pr\xE6cist p\xE5 dansk.`;
