      to: from,
      source: "agent",
      type: "Message",
      message: result.content,
      timestamp: (/* @__PURE__ */ new Date()).toISOString(),
      ...threadId ? { thread_id: threadId } : {},
      metadata: { provider: result.provider, model: result.model, duration_ms: result.duration_ms }
