// src/routes/audit.ts
import { Router as Router12 } from "express";

// src/audit.ts
init_redis();
init_logger();
var REDIS_KEY6 = "orchestrator:audit";
var MAX_ENTRIES = 1e3;
var TTL_SECONDS5 = 30 * 24 * 3600;
var memoryAudit = [];
async function logAudit(entry) {
  try {
    if (isRedisEnabled()) {
      const redis2 = getRedis();
      if (redis2) {
        await redis2.lpush(REDIS_KEY6, JSON.stringify(entry));
        await redis2.ltrim(REDIS_KEY6, 0, MAX_ENTRIES - 1);
        await redis2.expire(REDIS_KEY6, TTL_SECONDS5);
        return;
      }
    }
  } catch (err) {
    logger.warn({ err: String(err) }, "Audit Redis write failed, using memory");
  }
  memoryAudit.unshift(entry);
  if (memoryAudit.length > MAX_ENTRIES) memoryAudit = memoryAudit.slice(0, MAX_ENTRIES);
}
async function getAuditLog(limit = 100, offset = 0) {
  try {
    if (isRedisEnabled()) {
      const redis2 = getRedis();
      if (redis2) {
        const raw = await redis2.lrange(REDIS_KEY6, offset, offset + limit - 1);
        return raw.map((r) => JSON.parse(r));
      }
    }
  } catch (err) {
    logger.warn({ err: String(err) }, "Audit Redis read failed, using memory");
  }
  return memoryAudit.slice(offset, offset + limit);
}
function auditMiddleware(req, res, next) {
  if (req.method === "GET" || req.method === "OPTIONS" || req.method === "HEAD") {
    next();
    return;
  }
  const start = Date.now();
  const originalEnd = res.end.bind(res);
  res.end = function(...args) {
    const duration = Date.now() - start;
    const actor = req.body?.agent_id ?? req.body?.from ?? "human";
    const pathParts = req.path.split("/").filter(Boolean);
    const entityType = pathParts[0] ?? "unknown";
    const entityId = pathParts[1] ?? req.body?.agent_id ?? "-";
    let action = `${req.method.toLowerCase()}_${entityType}`;
    if (req.path.includes("/register")) action = "register";
    else if (req.path.includes("/call")) action = "tool_call";
    else if (req.path.includes("/execute")) action = "chain_execute";
    else if (req.path.includes("/message")) action = "chat_message";
    else if (req.path.includes("/heartbeat")) action = "heartbeat";
    else if (req.path.includes("/run")) action = "cron_trigger";
    const entry = {
      id: `aud-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 6)}`,
      timestamp: (/* @__PURE__ */ new Date()).toISOString(),
      actor,
      action,
      entity_type: entityType,
      entity_id: String(entityId),
      method: req.method,
      path: req.path,
      status: res.statusCode,
      duration_ms: duration
    };
    if (action !== "heartbeat") {
      logAudit(entry).catch(() => {
      });
    }
    return originalEnd(...args);
  };
  next();
}

// src/routes/audit.ts
var auditRouter = Router12();
auditRouter.get("/log", async (req, res) => {
  const limit = Math.min(parseInt(req.query.limit) || 100, 500);
  const offset = parseInt(req.query.offset) || 0;
  const entries = await getAuditLog(limit, offset);
  const actor = req.query.actor;
  const action = req.query.action;
  const entityType = req.query.entity_type;
  let filtered = entries;
  if (actor) filtered = filtered.filter((e2) => e2.actor === actor);
  if (action) filtered = filtered.filter((e2) => e2.action === action);
  if (entityType) filtered = filtered.filter((e2) => e2.entity_type === entityType);
  res.json({ success: true, data: { entries: filtered, total: filtered.length, limit, offset } });
});

// src/routes/tool-output.ts
init_redis();
init_logger();
import { Router as Router13 } from "express";
var toolOutputRouter = Router13();
var TOOL_OUTPUT_PREFIX2 = "orchestrator:tool-output:";
var ID_PATTERN = /^[a-f0-9-]{36}$/;
toolOutputRouter.get("/:id", async (req, res) => {
  const id = req.params.id;
  if (!ID_PATTERN.test(id)) {
    res.status(400).json({
      success: false,
      error: { code: "INVALID_ID", message: "Tool output ID must be a UUID", status_code: 400 }
    });
    return;
  }
  const redis2 = getRedis();
  if (!redis2) {
    res.status(503).json({
      success: false,
      error: { code: "REDIS_UNAVAILABLE", message: "Tool output store not available", status_code: 503 }
    });
    return;
  }
  try {
    const raw = await redis2.get(`${TOOL_OUTPUT_PREFIX2}${id}`);
    if (!raw) {
      res.status(404).json({
        success: false,
        error: { code: "NOT_FOUND", message: "Tool output not found or expired", status_code: 404 }
      });
      return;
    }
    const parsed = JSON.parse(raw);
    const ttl = await redis2.ttl(`${TOOL_OUTPUT_PREFIX2}${id}`);
    res.json({
      success: true,
      data: {
        ...parsed,
        ttl_remaining_seconds: ttl
      }
    });
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    logger.warn({ id, error: message }, "Tool output fetch failed");
    res.status(500).json({
      success: false,
      error: { code: "FETCH_FAILED", message, status_code: 500 }
    });
  }
});
toolOutputRouter.get("/:id/raw", async (req, res) => {
  const id = req.params.id;
  if (!ID_PATTERN.test(id)) {
    res.status(400).json({ success: false, error: { code: "INVALID_ID", message: "UUID required", status_code: 400 } });
    return;
  }
  const redis2 = getRedis();
  if (!redis2) {
    res.status(503).json({ success: false, error: { code: "REDIS_UNAVAILABLE", message: "Tool output store not available", status_code: 503 } });
    return;
  }
  try {
    const raw = await redis2.get(`${TOOL_OUTPUT_PREFIX2}${id}`);
    if (!raw) {
      res.status(404).type("text/plain").send("Not found or expired");
      return;
    }
    const parsed = JSON.parse(raw);
    res.type("text/plain; charset=utf-8").send(String(parsed.content ?? ""));
  } catch (err) {
    res.status(500).type("text/plain").send(`Error: ${err instanceof Error ? err.message : String(err)}`);
  }
});

