init_logger();
var phantomBomRouter = Router52();
var activeExtractions = 0;
var MAX_CONCURRENT3 = 3;
phantomBomRouter.post("/extract", async (req, res) => {
  const { repo_url, source_type = "git" } = req.body;
  if (!repo_url || typeof repo_url !== "string") {
    res.status(400).json({ success: false, error: { code: "MISSING_REPO_URL", message: "repo_url is required", status_code: 400 } });
    return;
  }
  if (!["git", "huggingface"].includes(source_type)) {
    res.status(400).json({ success: false, error: { code: "INVALID_SOURCE_TYPE", message: "source_type must be git or huggingface", status_code: 400 } });
    return;
  }
  if (activeExtractions >= MAX_CONCURRENT3) {
    res.status(429).json({ success: false, error: { code: "TOO_MANY_EXTRACTIONS", message: `Max ${MAX_CONCURRENT3} concurrent extractions. Try again shortly.`, status_code: 429 } });
    return;
  }
  const runId = `pbom-${Date.now()}-${Math.random().toString(36).substring(2, 8)}`;
  activeExtractions++;
  extractPhantomBOM(repo_url, source_type, runId).catch((err) => logger.error({ runId, err: String(err) }, "Async PhantomBOM extraction failed")).finally(() => {
    activeExtractions--;
  });
  res.json({
    success: true,
    run_id: runId,
    status: "running",
    poll: `/api/phantom-bom/runs/${runId}`,
    message: "Extraction started. Poll the run endpoint for status."
  });
});
phantomBomRouter.post("/extract/sync", async (req, res) => {
  const { repo_url, source_type = "git" } = req.body;
  if (!repo_url || typeof repo_url !== "string") {
    res.status(400).json({ success: false, error: { code: "MISSING_REPO_URL", message: "repo_url is required", status_code: 400 } });
    return;
  }
  if (!["git", "huggingface"].includes(source_type)) {
    res.status(400).json({ success: false, error: { code: "INVALID_SOURCE_TYPE", message: "source_type must be git or huggingface", status_code: 400 } });
    return;
  }
  if (activeExtractions >= MAX_CONCURRENT3) {
    res.status(429).json({ success: false, error: { code: "TOO_MANY_EXTRACTIONS", message: `Max ${MAX_CONCURRENT3} concurrent extractions.`, status_code: 429 } });
    return;
  }
  activeExtractions++;
  try {
    const bom = await extractPhantomBOM(repo_url, source_type);
    res.json({ success: true, bom });
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    logger.error({ repo_url, err: msg }, "Sync PhantomBOM extraction failed");
    res.status(500).json({ success: false, error: { code: "EXTRACTION_FAILED", message: msg, status_code: 500 } });
  } finally {
    activeExtractions--;
  }
});
